const item = items[0].json;

// helper para ler caminho aninhado tipo "vinculo.inicio"
function getPath(obj, path) {
  return path.split('.').reduce((acc, key) => (acc == null ? undefined : acc[key]), obj);
}

const schemaCampos = {
  data_admissao:      { label: "Data de admissão",                     origem: "triagem", path: "vinculo.inicio" },
  data_saida:         { label: "Data de saída (ou 'ainda trabalha')",  origem: "triagem", path: "vinculo.fim" },
  salario:            { label: "Salário",                              origem: "triagem", path: "vinculo.salario_medio" },
  tipo_rescisao:      { label: "Tipo de rescisão",                     origem: "triagem", path: "rescisao.tipo" },
  horas_extras:       { label: "Fazia horas extras",                   origem: "triagem", path: "jornada.fazia_horas_extras" },
  fgts_depositado:    { label: "FGTS depositado corretamente",         origem: "triagem", path: "direitos.fgts_depositado" },

  // 🚩 aproximação — confirmar se ferias_terco cobre o que vocês querem dizer com "férias vencidas"
  ferias_vencidas:    { label: "Férias vencidas",                      origem: "triagem", path: "direitos.ferias_terco" },

  assedio:            { label: "Assédio moral",                        origem: "triagem", path: "agravantes.assedio" },

  // 🚩 aproximação — só cobre doenca_afastamento, não acidente_trabalho
  doenca_ocupacional: { label: "Doença ocupacional",                   origem: "triagem", path: "agravantes.doenca_afastamento" },

  // 🚩 aproximação — só cobre gestante, não estabilidade acidentária/sindical
  estabilidade:       { label: "Estabilidade violada",                 origem: "triagem", path: "agravantes.gestante" },

  desvio_funcao:      { label: "Desvio de função",                     origem: "peticao", path: "vinculo.desvio_funcao" },
  trabalho_fds:       { label: "Trabalho aos finais de semana",        origem: "peticao", path: "jornada.trabalho_fim_semana" },
  controle_ponto:     { label: "Controle de ponto (digital/manual)",   origem: "peticao", path: "jornada.controle_ponto" },
  outros_direitos:    { label: "Outros direitos não conversados",      origem: "peticao", path: "outros_direitos_mencionados" },
};

const schemaDocumentos = {
  ctps:             "CTPS",
  trct:             "TRCT",
  extrato_fgts:     "Extrato do FGTS",
  contracheque:     "Contracheques",
  prova_agravante:  "Provas de agravante",
};

const dados = item.triagem || {};
const documentos = item.documentos || [];

const coletadosTriagem = [];
const coletadosPeticao = [];
const faltantes = [];

for (const [campo, info] of Object.entries(schemaCampos)) {
  const valor = getPath(dados, info.path);

  if (valor === undefined || valor === null || valor === "") {
    faltantes.push(`${campo}: ${info.label}`);
  } else if (info.origem === "triagem") {
    coletadosTriagem.push(`${info.label}: ${valor}`);
  } else {
    coletadosPeticao.push(`${info.label}: ${valor}`);
  }
}

// jornada_detalhada é composto de dois campos (horario_real + intervalo) —
// só considera completo se os DOIS existirem
const horarioReal = getPath(dados, "jornada.horario_real");
const intervalo = getPath(dados, "jornada.intervalo");

if (horarioReal && intervalo) {
  coletadosPeticao.push(`Jornada (entrada/intervalo/saída): ${horarioReal}, intervalo: ${intervalo}`);
} else {
  faltantes.push("jornada_detalhada: Jornada (entrada/intervalo/saída)");
}

const tiposRecebidos = new Set(
  documentos.map(d => d.tipo_documento).filter(Boolean)
);

const documentosRecebidos = [];
const documentosFaltantes = [];

for (const [tipo, label] of Object.entries(schemaDocumentos)) {
  if (tiposRecebidos.has(tipo)) {
    documentosRecebidos.push(label);
  } else {
    documentosFaltantes.push(label);
  }
}

return [
  {
    json: {
      id: item.id,
      nome: item.cliente_nome_completo || item.nome,
      telefone: item.telefone,
      etapa: item.etapa,

      entrevista_pode_iniciar: item.area_juridica === "trabalhista" && item.etapa === "fechado",

      dados_coletados_triagem: coletadosTriagem.length
        ? coletadosTriagem.join("\n")
        : "Nenhum dado de triagem encontrado ainda.",

      dados_coletados_peticao: coletadosPeticao.length
        ? coletadosPeticao.join("\n")
        : "Nenhum dado coletado nesta entrevista ainda.",

      campos_faltantes: faltantes.length
        ? faltantes.join("\n")
        : "Nenhum — todos os campos já foram coletados.",

      documentos_recebidos: documentosRecebidos.length
        ? documentosRecebidos.join(", ")
        : "Nenhum documento recebido ainda.",

      documentos_faltantes: documentosFaltantes.length
        ? documentosFaltantes.join(", ")
        : "Nenhum — todos os documentos já foram recebidos.",
    },
  },
];
